BEGIN;

-- ─── approved_tags — Northwind / Discharge Conveyor CV-200 allowlist seed ────
--
-- SEPARATE from the garage seed (tools/seeds/approved_tags_conveyor.sql) — that
-- one stays bound to enterprise.home_garage.conveyor_lab.conveyor_1 and is NOT
-- touched. This file ADDS a Northwind-tenant allowlist for the SAME physical rig
-- (Micro820 + GS10), mapped onto the CV-200 UNS subtree. Both tenants' allowlists
-- coexist (PK is (tenant_id, source_system, source_tag_path)); the gateway timer
-- publishes the rig tags a SECOND time as the Northwind tenant — ADD, never
-- repoint. See docs/handoffs/2026-06-28-plc-laptop-northwind-cv200-perspective.md.
--
-- Seeds the per-tenant SECURITY allowlist the mira-relay ingest endpoint
-- (POST /api/v1/tags/ingest) enforces FAIL-CLOSED before persisting tag readings
-- to tag_events + live_signal_cache. Without this seed every HMAC-signed batch
-- from the Ignition tag-stream timer (as the Northwind tenant) is rejected and
-- the CV-200 tile never gets a fresh live_signal_cache row → freshness dot gray.
--
-- KEY MATCH — the relay's hot-path query is
--   WHERE tenant_id=? AND source_system=? AND normalized_tag_path=? AND enabled=true
-- so normalized_tag_path MUST equal what mira-relay/tag_ingest.normalize_tag_path
-- produces. These values are byte-identical to the garage seed's (same rig tags,
-- same source paths) — only uns_path + notes differ. Pinned by
-- tests/test_northwind_cv200_seed_and_config.py.
--
-- UNS subtree — every row points at the CV-200 dotted ltree path so the Command
-- Center freshness rollup picks them up under the CV-200 node (the binding key).
--
-- TENANT — __TENANT_ID__ placeholder is replaced at apply time (apply-seeds.yml /
-- a -v override) with the Northwind tenant UUID 00000000-0000-0000-0000-0000000000b1.
--
-- Idempotent — re-running is safe via ON CONFLICT … DO UPDATE SET enabled=true.

  -- ── added 2026-06-28: 11 MIRA_IOCheck tags the staged NorthwindBottling Perspective project binds ──
  -- These were missing from the initial seed; without them the relay drops them fail-closed and the
  -- CV-200 view's inputs/outputs/motor-rpm/power/torque/warn-code panels show no live data.
  -- Pinned against the project's actual bindings by tests/test_northwind_cv200_seed_and_config.py.
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/Inputs/DI_00',                    'default_mira_iocheck_inputs_di_00',                    'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/Inputs/DI_01',                    'default_mira_iocheck_inputs_di_01',                    'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/Inputs/DI_04',                    'default_mira_iocheck_inputs_di_04',                    'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/Outputs/DO_00',                   'default_mira_iocheck_outputs_do_00',                   'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/Outputs/DO_01',                   'default_mira_iocheck_outputs_do_01',                   'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/Outputs/DO_03',                   'default_mira_iocheck_outputs_do_03',                   'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/VFD/vfd_freq_cmd',                'default_mira_iocheck_vfd_vfd_freq_cmd',                'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/VFD/vfd_motor_rpm',               'default_mira_iocheck_vfd_vfd_motor_rpm',               'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/VFD/vfd_power',                   'default_mira_iocheck_vfd_vfd_power',                   'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/VFD/vfd_torque',                  'default_mira_iocheck_vfd_vfd_torque',                  'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28'),
  ('__TENANT_ID__'::uuid, 'ignition', '[default]MIRA_IOCheck/VFD/vfd_warn_code',               'default_mira_iocheck_vfd_vfd_warn_code',               'enterprise.riverside.area.packaging.line.line1.equipment.discharge_conveyor_cv200'::ltree, true, 'Northwind CV-200 live rig — staged Perspective binding 2026-06-28')

ON CONFLICT (tenant_id, source_system, source_tag_path) DO UPDATE
  SET normalized_tag_path = EXCLUDED.normalized_tag_path,
      uns_path = EXCLUDED.uns_path,
      enabled = true,
      notes = EXCLUDED.notes,
      updated_at = now();

COMMIT;
